import { existsSync, mkdirSync, readdirSync, readFileSync, writeFileSync } from 'node:fs';
import { join, resolve } from 'node:path';
import { checkMark, tildeMark } from '#/utils/console';

const drizzleDir = join(process.cwd(), 'drizzle');

/**
 * Warning header prepended to all generated migration SQL files.
 * Signals that the file is auto-generated.
 */
export const generatedMigrationHeader = `-- ⚠️ AUTO-GENERATED — DO NOT EDIT THIS FILE DIRECTLY
-- This migration is generated by a script in backend/scripts/migrations/.
-- To make changes, edit the generator script and re-run it.
-- The user will handle migration generation and application.
--
`;

interface MigrationResult {
  folderName: string;
  path: string;
  tag: string;
  /** 'created' = new migration; 'evolved' = content changed; 'unchanged' = SQL identical. */
  action: 'created' | 'evolved' | 'unchanged';
}

/**
 * Generate a timestamp in Drizzle v1 format (YYYYMMDDHHmmss).
 */
function generateTimestamp(): string {
  const now = new Date();
  return now.toISOString().replace(/[-:T]/g, '').slice(0, 14);
}

/**
 * Get all migration folders sorted by timestamp.
 */
export function getMigrationFolders(): string[] {
  if (!existsSync(drizzleDir)) return [];
  return readdirSync(drizzleDir, { withFileTypes: true })
    .filter((entry) => entry.isDirectory() && /^\d{14}_/.test(entry.name))
    .map((entry) => entry.name)
    .sort();
}

/**
 * Find the latest migration folder by tag suffix. Migrations can evolve (multiple folders
 * share a tag), so this returns the most recent match.
 */
export function findMigrationByTag(tagSuffix: string): string | undefined {
  const matches = getMigrationFolders().filter((folder) => folder.endsWith(`_${tagSuffix}`));
  return matches.length > 0 ? matches[matches.length - 1] : undefined;
}

/**
 * Get the latest snapshot from existing migrations.
 */
export function getLatestSnapshot(): object | null {
  const folders = getMigrationFolders();
  for (let i = folders.length - 1; i >= 0; i--) {
    const snapshotPath = join(drizzleDir, folders[i], 'snapshot.json');
    if (existsSync(snapshotPath)) {
      return JSON.parse(readFileSync(snapshotPath, 'utf-8'));
    }
  }
  return null;
}

/**
 * Resolve SQL content from either a file path or inline SQL string.
 * @param sqlOrPath - SQL content or path to a .sql file
 */
export function resolveSqlContent(sqlOrPath: string): string {
  const possiblePath = resolve(sqlOrPath);
  if (existsSync(possiblePath) && possiblePath.endsWith('.sql')) {
    return readFileSync(possiblePath, 'utf-8');
  }
  return sqlOrPath;
}

/**
 * Add or update a SQL migration in the Drizzle migrations folder (v1 format).
 *
 * When a migration with the tag already exists: identical SQL → action 'unchanged'; changed
 * SQL → action 'evolved', leaving the old folder untouched and writing a fresh timestamped
 * folder with the new SQL.
 *
 * @param sql - SQL content, not a file path (use resolveSqlContent first if needed)
 */
export function upsertMigration(tag: string, sql: string): MigrationResult {
  // Normalize tag by removing leading timestamps/underscores if present.
  const normalizedTag = tag.replace(/^\d+_/, '');

  // Prepend the auto-generation warning header.
  const finalSql = generatedMigrationHeader + sql;

  // Check if a migration with this tag already exists.
  const existingFolder = findMigrationByTag(normalizedTag);

  if (existingFolder) {
    const folderPath = join(drizzleDir, existingFolder);
    const migrationPath = join(folderPath, 'migration.sql');

    // Compare content; if unchanged, skip entirely.
    if (existsSync(migrationPath)) {
      const existingSql = readFileSync(migrationPath, 'utf-8');
      if (existingSql === finalSql) {
        return { folderName: existingFolder, path: folderPath, tag: normalizedTag, action: 'unchanged' };
      }
    }

    // Preserve the old migration and create a new one with a fresh timestamp.
    const timestamp = generateTimestamp();
    const newFolderName = `${timestamp}_${normalizedTag}`;
    const newFolderPath = join(drizzleDir, newFolderName);

    mkdirSync(newFolderPath, { recursive: true });
    writeFileSync(join(newFolderPath, 'migration.sql'), finalSql);

    // Copy the snapshot from the latest migration.
    const latestSnapshot = getLatestSnapshot();
    if (latestSnapshot) {
      writeFileSync(join(newFolderPath, 'snapshot.json'), JSON.stringify(latestSnapshot, null, 2));
    }

    return { folderName: newFolderName, path: newFolderPath, tag: normalizedTag, action: 'evolved' };
  }

  // Create a new migration folder with Drizzle v1 naming convention.
  const timestamp = generateTimestamp();
  const folderName = `${timestamp}_${normalizedTag}`;
  const folderPath = join(drizzleDir, folderName);

  // Create the folder and write the migration file.
  mkdirSync(folderPath, { recursive: true });
  writeFileSync(join(folderPath, 'migration.sql'), finalSql);

  // Copy the latest snapshot; manual SQL migrations don't change Drizzle schema.
  const latestSnapshot = getLatestSnapshot();
  if (latestSnapshot) {
    writeFileSync(join(folderPath, 'snapshot.json'), JSON.stringify(latestSnapshot, null, 2));
  }

  return { folderName, path: folderPath, tag: normalizedTag, action: 'created' };
}

/**
 * Log a migration result to the console.
 */
export function logMigrationResult(result: MigrationResult, context?: string): void {
  console.info('');
  const contextStr = context ? ` (${context})` : '';

  switch (result.action) {
    case 'created':
      console.info(`${checkMark} Migration created${contextStr}: drizzle/${result.folderName}/migration.sql`);
      break;
    case 'evolved':
      console.info(`${tildeMark} Migration evolved${contextStr}: drizzle/${result.folderName}/migration.sql (old version preserved)`);
      break;
    case 'unchanged':
      console.info(`${checkMark} Migration unchanged${contextStr}: drizzle/${result.folderName}/migration.sql`);
      break;
  }
}
